update public.lessons l set enhancements = $ench${"industryStory":"A tester found a serious bug, messaged it in a chat channel, and moved on. It scrolled away, nobody logged it, and it shipped. The lesson: a defect that is not tracked through a clear lifecycle effectively does not exist. Process is what turns \"I found a bug\" into \"the bug got fixed\".","visualAid":{"type":"flow","title":"The defect lifecycle","steps":[{"label":"New"},{"label":"Assigned"},{"label":"Open / In progress"},{"label":"Fixed"},{"label":"Retest"},{"label":"Closed"}],"caption":"Plus Reopened / Deferred / Rejected where applicable."},"davidTip":"Know the lifecycle and keep statuses honest in real time. As a QA lead, the testers I trust most are the ones whose board always reflects reality — I can look at it and know exactly where every defect stands without asking.","miniChallenge":"Write the lifecycle a defect would follow from the moment you find it to closure, naming who acts at each stage.","modelAnswer":"## Example\nNew (tester logs it) → Assigned (lead/dev picks it up) → In progress (dev fixes) → Fixed (dev marks ready) → Retest (tester verifies) → Closed (tester confirms). If it fails retest: Reopened → back to In progress."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 3 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"A developer spent half a day unable to reproduce a \"login broken\" bug because the report had no steps, no environment and no evidence. A two-minute, well-written report would have saved that half-day. Bug reports are how testers turn observations into fast fixes.","badGood":{"label":"a bug report","bad":"Title: Login broken\nDescription: It doesn't work, please fix.","good":"Title: Login: valid users on Safari get \"server error\" after submitting\nEnvironment: Safari 17, build 4.2.1, staging\nSteps: 1) Go to /login 2) Enter valid credentials 3) Click Sign in\nExpected: Lands on dashboard\nActual: \"500 server error\" page\nEvidence: screenshot + console log attached\nSeverity: High · Priority: High"},"davidTip":"Write the report for the person fixing it. A clear title, minimal reproducible steps, expected vs actual, environment and evidence — that is the difference between a fix today and a \"cannot reproduce\" tomorrow. Clarity is a professional courtesy that gets your bugs fixed faster.","miniChallenge":"Find any real issue (or imagine one) and write a full bug report: title, environment, steps, expected, actual, evidence note, severity and priority.","modelAnswer":"## Example\nTitle: Checkout: SAVE10 code charges full price on mobile Safari\nEnvironment: iPhone Safari, build 5.1, prod-like\nSteps: 1) Add item 2) Apply SAVE10 3) Pay\nExpected: 10% discount applied\nActual: Full price charged; no discount shown\nEvidence: screen recording attached\nSeverity: High · Priority: High","managersReview":{"intro":"If I received this bug report as a QA lead, I would check:","strengths":["Specific, scannable title","Minimal reproducible steps","Expected vs actual stated separately","Evidence attached"],"gaps":["Vague title (\"broken\")","No environment or build","No evidence; emotional language"],"improvements":["Lead the title with where + what","Always capture build/browser","Attach a screenshot or recording"]},"resourcePreview":{"name":"Bug Report Template","purpose":"A professional bug-report structure that gets defects fixed faster.","whenToUse":"Use it for every defect you log — and for your portfolio bug-report pack.","formats":["DOCX","PDF"]},"portfolioBuilder":"A professional bug report is a key portfolio artefact. Save your best one — it is concrete proof you can communicate defects clearly, which every hiring manager values."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 3 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"A tester marked a cosmetic typo as \"Critical\" and a payment failure as \"Medium\". The team lost trust in their judgement. Severity and priority are different lenses, and using them well is what makes your reports actionable.","visualAid":{"type":"matrix","title":"Severity × Priority","colLabels":["Low priority","High priority"],"rowLabels":["High severity","Low severity"],"cells":[[{"label":"Rare crash in edge case","level":"high"},{"label":"Payment fails — fix now","level":"critical"}],[{"label":"Minor typo on hidden page","level":"low"},{"label":"Typo on homepage hero","level":"medium"}]],"caption":"Severity = technical impact. Priority = business urgency. They are independent."},"davidTip":"Severity is how badly it breaks; priority is how soon the business needs it fixed. A homepage typo can be low severity but high priority. Keeping them separate — and justifying both by impact — is what makes your triage credible.","miniChallenge":"For three bugs (a homepage logo typo, a checkout crash, a rare error in an admin-only report), assign severity and priority and justify each in one line.","modelAnswer":"## Example\n- Homepage logo typo: Severity Low, Priority High (visible to all, cheap to fix, reputational)\n- Checkout crash: Severity High, Priority High (blocks revenue)\n- Rare admin report error: Severity Medium, Priority Low (few users, workaround exists)","resourcePreview":{"name":"Defect Severity vs Priority Guide","purpose":"A reference for classifying defects consistently.","whenToUse":"Use it when triaging so your severity/priority calls are defensible.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 3 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"industryStory":"An intermittent bug appeared \"randomly\" until a tester isolated it: it only happened for users in a different timezone, after midnight UTC. Reproducing and isolating defects is detective work — and it is what turns a vague report into a fixable one.","visualAid":{"type":"flow","title":"Isolating a defect","steps":[{"label":"Reproduce","detail":"find reliable steps"},{"label":"Narrow","detail":"change one variable at a time"},{"label":"Identify trigger","detail":"data? user? environment?"},{"label":"Document","detail":"exact conditions"}]},"davidTip":"When something is \"intermittent\", it usually is not random — there is a variable you have not pinned down yet. Change one thing at a time (browser, data, account, timing) until it becomes reliable. A reproducible bug is a fixable bug.","miniChallenge":"Describe how you would isolate a bug that \"sometimes\" happens on checkout. List four variables you would test one at a time.","modelAnswer":"## Example\nVariables to isolate: payment method (card vs PayPal), browser (Chrome vs Safari), cart contents (single vs multiple items), account type (guest vs logged-in). Hold everything constant, change one, and watch when the bug appears — that exposes the trigger."}$ench$::jsonb
