update public.lessons l set enhancements = $ench${"industryStory":"A team's backlog had 300 open defects and no order to them. Triage meetings turned chaotic. A simple, regular triage process — review, prioritise, assign, track — is what keeps defect management from collapsing under its own weight.","visualAid":{"type":"comparison","title":"A simple triage flow","headers":["Step","Question","Outcome"],"rows":[["Review","Is it valid and clear?","Accept / send back"],["Prioritise","How urgent vs severe?","Set severity & priority"],["Assign","Who owns the fix?","Assign to a dev"],["Track","Is it progressing?","Update status; retest when fixed"]]},"davidTip":"Good triage is less about tooling and more about rhythm. A short, regular triage where every new defect is reviewed, prioritised and assigned keeps the backlog honest. As a QA lead, I would rather have a small triaged backlog than a huge untriaged one.","miniChallenge":"Sketch how you would run a 15-minute defect triage: what you would review, in what order, and what each defect should leave the meeting with.","modelAnswer":"## Example\nOrder by severity. For each new defect: confirm it is valid and reproducible, set severity and priority, assign an owner, and agree whether it blocks the release. Every defect leaves with an owner, a priority and a clear status."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
