update public.lessons l set enhancements = $ench${"davidTip":"For this assignment, quality beats quantity. Ten clear, well-classified bug reports demonstrate more skill than thirty vague ones. Treat each report as something a developer could act on immediately.","miniChallenge":"Before submitting, run each of your bug reports through one question: \"Could a developer reproduce and fix this without asking me anything?\" Fix any that fail.","managersReview":{"intro":"If I received your defect pack as a QA lead, I would look for:","strengths":["Reproducible steps and clear titles","Sensible, justified severity/priority","Evidence attached"],"gaps":["Vague or emotional descriptions","Missing environment/steps","Severity and priority confused"],"improvements":["Make every report independently reproducible","Justify severity and priority by impact","Attach evidence for each"]},"portfolioBuilder":"This defect pack joins your test case pack as core portfolio evidence. Together they show you can both design coverage and communicate what you find — the two halves of practical QA."}$ench$::jsonb
